texttool_globals_dialog_message___abort_loging_cancel_confirmation_text = TextObject(bs_BA="Želite li prekinuti prijavu?", cs_CZ="Chcete zrušit svou registraci?", da_DK="Vil du afbryde login?", de_DE="Möchtest du die Anmeldung abbrechen?", el_GR="Θέλετε να ματαιώσετε τη σύνδεση (log in);", en_GB="Would you like to cancel the login?", es_ES="¿Cancelar el inicio de sesión?", fi_FI="Haluatko keskeyttää kirjautumisen?", fr_FR="Souhaitez-vous annuler la connexion?", hr_HR="Želite li prekinuti prijavu?", hu_HU="Meg szeretnéd szakítani a bejelentkezést?", it_IT="Annullare il login?", nl_NL="Wil je het aanmelden annuleren?", no_NO="Vil du avbryte påloggingen?", pl_PL="Anulować logowanie?", pt_PT="Queres cancelar o registo?", ro_RO="Doriţi într-adevăr să întrerupeţi autentificarea?", ru_RU="Хотите отменить вход?", sk_SK="Chcete zrušiť prihlásenie?", sl_SI="Ali res želite prekiniti prijavo?", sr_RS="Da li želite da prekinete prijavu?", sv_SE="Vill du avbryta inloggningen`?", tr_TR="Oturum açmayı iptal etmek istiyor musun?", uk_UA="Хочете скасувати вхід?")
texttool_globals_dialog_message___add_online_user_privacy_warning_dialog = TextObject(bs_BA="Za prijavu vašeg myAudi korisnika je neophodna veza sa internetom. Želite li sada\nuspostaviti vezu sa internetom?", cs_CZ="Pro přihlášení svým uživatelem myAudi potřebujete připojení k internetu. Chcete\nnyní vytvořit připojení k internetu?", da_DK="Internetforbindelse er nødvendigt for at kunne logge din myAudi-bruger på. Vil du\noprette internetforbindelse nu?", de_DE="Für die Anmeldung deines myAudi Nutzers ist eine Internetverbindung notwendig.\nMöchtest du jetzt eine Internetverbindung herstellen?", el_GR="Για τη σύνδεση (log in) με τον λογαριασμό σας χρήστη myAudi απαιτείται σύνδεση με\nτο διαδίκτυο. Θέλετε να δημιουργήσετε τώρα μια σύνδεση με το διαδίκτυο;", en_GB="An Internet connection is required to log in with your myAudi user. Would you like\nto establish an Internet connection now?", es_ES="Para iniciar sesión con su usuario myAudi necesita conexión a Internet. ¿Desea\nconectarse a Internet?", fi_FI="myAudi-käyttäjätilille kirjautumiseen tarvitaan internetyhteys. Haluatko nyt\nmuodostaa internetyhteyden?", fr_FR="Une connexion Internet est requise pour pouvoir vous connecter à votre profil\nutilisateur myAudi. Souhaitez-vous établir une connexion Internet maintenant?", hr_HR="Za prijavu myAudi korisničkog računa potrebna je veza s internetom. Želite li sada\nuspostaviti vezu s internetom?", hu_HU="A myAudi felhasználód bejelentkezéséhez internetkapcsolat szükséges. Szeretnél\nmost csatlakozni az internethez?", it_IT="Per effettuare il login all'utente myAudi è necessario un collegamento internet.\nDesidera stabilire adesso un collegamento internet?", nl_NL="Voor het aanmelden van je myAudi gebruiker is verbinding met het internet vereist.\nWil je nu verbinding met het internet maken?", no_NO="Du må ha internettforbindelse for å logge på myAudi-brukeren din. Vil du opprette\ninternettforbindelse nå?", pl_PL="Do zalogowania Twojego użytkownika myAudi wymagane jest połączenie z\nInternetem. Czy chcesz nawiązać połączenie z Internetem teraz?", pt_PT="Para fazer login com o teu utilizador myAudi, é necessária uma ligação à Internet.\nQueres estabelecer agora uma ligação à Internet?", ro_RO="Pentru autentificarea utilizatorului myAudi este necesară o conexiune la Internet.\nDoriţi să realizaţi acum o conexiune la Internet?", ru_RU="Для входа пользователя myAudi требуется интернет-соединение. Хотите\nустановить интернет-соединение сейчас?", sk_SK="Na prihlásenie vášho používateľa myAudi sa vyžaduje internetové pripojenie. Chcete\nteraz vytvoriť internetové pripojenie?", sl_SI="Za prijavo uporabnika myAudi je potrebna internetna povezava. Ali želite zdaj\nvzpostaviti internetno povezavo?", sr_RS="Za prijavu vašeg myAudi korisnika je neophodna veza sa internetom. Da li želite\nsada uspostaviti vezu sa internetom?", sv_SE="För att logga in med din myAudi-användare behövs en internetanslutning. Vill du\nansluta till internet nu?", tr_TR="myAudi kullanıcınla oturum açmak için bir internet bağlantısı gereklidir. Şimdi\ninternete bağlanmak istiyor musun?", uk_UA="Для входу користувача myAudi потрібне з’єднання з Інтернетом. Бажаєте\nвстановити з’єднання з Інтернетом зараз?")
texttool_globals_dialog_message___confirm_spin_privacy_warning_dialog = TextObject(bs_BA="Za dodatnu provjeru vašeg myAudi PIN-a je neophodna veza sa internetom. Želite li\nsada uspostaviti vezu sa internetom?", cs_CZ="Pro další kontrolu svého PINu myAudi potřebujete připojení k internetu. Chcete nyní\nvytvořit připojení k internetu?", da_DK="Internetforbindelse er nødvendigt for at kunne kontrollere din myAudi-pinkode\nyderligere. Vil du oprette internetforbindelse nu?", de_DE="Für eine weitere Prüfung deiner myAudi PIN wird eine Internetverbindung benötigt.\nMöchtest du jetzt eine Internetverbindung herstellen?", el_GR="Για τον περαιτέρω έλεγχο του myAudi PIN σας απαιτείται σύνδεση με το διαδίκτυο.\nΘέλετε να δημιουργήσετε τώρα μια σύνδεση με το διαδίκτυο;", en_GB="An Internet connection is required for a further check of your myAudi PIN. Would\nyou like to establish an Internet connection now?", es_ES="Una comprobación más exhaustiva de su PIN myAudi requiere conexión a Internet.\n¿Desea conectarse a Internet?", fi_FI="myAudi-PIN-koodin tarkastamista varten tarvitaan internetyhteys. Haluatko nyt\nmuodostaa internetyhteyden?", fr_FR="Une connexion Internet est requise pour une vérification complémentaire de votre\ncode PIN myAudi. Souhaitez-vous établir une connexion Internet maintenant?", hr_HR="Za daljnju provjeru vašeg myAudi PIN-a potrebna je internetska veza. Želite li sada\nuspostaviti internetsku vezu?", hu_HU="A myAudi PIN-kódod további ellenőrzéséhez internetkapcsolat szükséges. Szeretnél\nmost csatlakozni az internethez?", it_IT="Per un'ulteriore verifica del Suo PIN myAudi è necessario un collegamento internet.\nDesidera stabilire adesso un collegamento internet?", nl_NL="Om je myAudi pincode verder te controleren, is verbinding met het internet vereist.\nWil je nu verbinding met het internet maken?", no_NO="En ny kontroll av myAudi-PIN krever internettforbindelse. Vil du opprette\ninternettforbindelse nå?", pl_PL="Do dalszej kontroli Twojego kodu PIN myAudi wymagane jest połączenie z\nInternetem. Czy chcesz nawiązać połączenie z Internetem teraz?", pt_PT="Para continuar a verificar o teu PIN myAudi, é necessária uma ligação à Internet.\nQueres estabelecer agora uma ligação à Internet?", ro_RO="Pentru verificarea suplimentară a codului PIN myAudi este necesară o conexiune la\nInternet. Doriţi să realizaţi acum o conexiune la Internet?", ru_RU="Для дальнейшей проверки PIN-кода myAudi требуется интернет-соединение.\nУстановить интернет-соединение сейчас?", sk_SK="Pre opätovnú kontrolu kódu PIN myAudi je potrebné internetové pripojenie. Chcete\nteraz vytvoriť internetové pripojenie?", sl_SI="Za dodatno preverjanje vaše PIN-kode myAudi je potrebna internetna povezava. Ali\nželite zdaj vzpostaviti internetno povezavo?", sr_RS="Za dodatnu proveru vašeg myAudi PIN-a neophodna je veza sa internetom. Da li\nželite sada uspostaviti vezu sa internetom?", sv_SE="För att ytterligare kontrollera din myAudi-PIN-kod behövs en internetanslutning.\nVill du ansluta till internet nu?", tr_TR="myAudi PIN'ini daha ayrıntılı kontrol etmek için bir internet bağlantısı gereklidir.\nŞimdi internete bağlanmak istiyor musun?", uk_UA="Для подальшої перевірки PIN-коду myAudi потрібне з'єднання з Інтернетом.\nБажаєте встановити з'єднання зараз?")
texttool_globals_dialog_message___delete_user_error_primary_user = TextObject(bs_BA="Glavni korisnik se ne može ukloniti. Prijavite se kao glavni korisnik da biste mogli\nizvršiti postupak brisanja ili resetujte sistem na fabričke postavke.", cs_CZ="Hlavního uživatele nelze odstranit. Přihlaste se jako hlavní uživatel a proveďte\nproces odstranění nebo obnovte tovární nastavení systému.", da_DK="Primær bruger kan ikke fjernes. Log på som primær bruger for at gennemføre\nsletningen, eller nulstil systemet til fabriksindstillingerne.", de_DE="Der Hauptnutzer kann nicht entfernt werden. Bitte melde dich als Hauptnutzer an,\num den Löschvorgang vorzunehmen, oder setze das System auf die\nWerkseinstellungen zurück.", el_GR="Δεν είναι εφικρή η αφαίρεση του βασικού χρήστη. Συνδεθείτε (log in) ως βασικός\nχρήστης, για να προβείτε στη διαδικασία διαγραφής ή επαναφέρετε το σύστημα στις\nεργοστασιακές ρυθμίσεις.", en_GB="The key user cannot be removed. Please log in as a key user to delete the key user or\nreset the system to factory settings.", es_ES="El usuario principal no se puede eliminar. Para borrarlo, inicie sesión como usuario\nprincipal o restablezca los ajustes de fábrica del sistema.", fi_FI="Pääkäyttäjää ei voida poistaa. Kirjaudu pääkäyttäjänä poistamisen suorittamiseksi\ntai palauta järjestelmä tehdasasetuksiin.", fr_FR="L'utilisateur principal ne peut pas être supprimé. Veuillez vous connecter en tant\nqu'utilisateur principal pour procéder à la suppression ou rétablissez les réglages\nd'usine du système.", hr_HR="Glavni korisnik se ne može ukloniti. Prijavite se kao glavni korisnik kako biste izvršili\nbrisanje ili poništite sustav na tvorničke postavke.", hu_HU="A főfelhasználó nem távolítható el. Jelentkezz be főfelhasználóként a törlési\nfolyamat végrehajtásához, vagy állítsd vissza a rendszert a gyári beállításokra.", it_IT="Non è possibile eliminare l'utente principale. Effettuare il login come utente\nprincipale per eseguire la cancellazione o ripristinare la configurazione iniziale del\nsistema.", nl_NL="De hoofdgebruiker kan niet worden verwijderd. Meld je als hoofdgebruiker aan om\nzelf het wissingsproces over te nemen of zet het systeem terug in de\nfabrieksinstellingen.", no_NO="Kan ikke fjerne hovedbrukeren. Logg på som hovedbruker for å utføre slettingen,\neller tilbakestill systemet til fabrikkinnstillingene.", pl_PL="Nie można usunąć użytkownika głównego. Zaloguj się jako użytkownik główny, aby\ndokonać usunięcia lub przywrócić ustawienia fabryczne systemu.", pt_PT="O utilizador principal não pode ser eliminado. Por favor, faz login como utilizador\nprincipal para realizares a eliminação ou repõe as configurações de fábrica do\nsistema.", ro_RO="Utilizatorul principal nu poate fi şters. Autentificaţi-vă ca utilizator principal, pentru\na efectua operaţia de ştergere sau resetaţi sistemul la setările din fabrică.", ru_RU="Основной пользователь не может быть удален. Чтобы выполнить удаление,\nвойдите в систему под именем основного пользователя или сбросьте заводские\nнастройки.", sk_SK="Hlavného používateľa nie je možné odstrániť. Prosím, prihláste sa ako hlavný\npoužívateľ, aby ste odstránili alebo resetovali systém na výrobné nastavenia.", sl_SI="Glavnega uporabnika ni mogoče odstraniti. Prijavite se kot glavni uporabnik, da\nizvedete brisanje ali sistem resetirate na tovarniške nastavitve.", sr_RS="Glavni korisnik ne može da se ukloni. Prijavite se kao glavni korisnik da biste mogli\nizvršiti postupak brisanja ili resetujte sistem na fabrička podešavanja.", sv_SE="Huvudanvändaren kan inte tas bort. Logga in som huvudanvändare för att ta bort\nanvändaren eller återställ systemet till fabriksinställningarna.", tr_TR="Ana kullanıcı kaldırılamaz. Silme işlemini gerçekleştirmek için lütfen ana kullanıcı\nolarak oturum aç veya sistemi fabrika ayarlarına sıfırla.", uk_UA="Основного користувача не можна видалити. Увійдіть як основний користувач,\nщоб виконати процес видалення або скинути систему до заводських\nналаштувань.")
texttool_globals_dialog_message___delete_user_warning_active_primary_user = TextObject(bs_BA="Želite li zaista ukloniti aktivnog glavnog korisnika %1 iz ovog vozila? Time će\nbiti izgubljene vaše spremljene individualne postavke i učitan gostujući korisnik.\nStatus glavnog korisnika ostaje.", cs_CZ="Opravdu chcete odstranit aktivního hlavního uživatele %1 z tohoto vozidla?\nVaše uložená individuální nastavení ve vozidle budou ztracena a bude načten\nhostující uživatel. Stav hlavního uživatele zůstane zachován.", da_DK="Vil du virkelig fjerne den aktive primære bruger %1 fra denne bil? Dermed går\ndine gemte individuelle indstillinger i bilen tabt, og gæstebrugeren indlæses.\nStatussen som primær bruger bibeholdes.", de_DE="Möchtest du den aktiven Hauptnutzer %1 wirklich aus diesem Fahrzeug\nentfernen? Damit gehen deine gespeicherten individuellen Einstellungen im\nFahrzeug verloren und der Gastnutzer wird geladen. Der Hauptnutzerstatus\nbleibt bestehen.", el_GR="Θέλετε σίγουρα να αφαιρέσετε τον ενεργό βασικό χρήστη %1 από αυτό το\nόχημα; Έτσι θα χαθούν οι αποθηκευμένες σας στο όχημα προσωπικές ρυθμίσεις και\nθα γίνει φόρτωση του χρήστη επισκέπτη. Η ιδιότητα ως βασικός χρήστης συνεχίζει να\nυφίσταται.", en_GB="Do you really want to remove the active key user %1 from this vehicle? This\nwill remove your saved custom settings and the guest account will be loaded. The\nstatus of the key user will remain in place.", es_ES="¿Realmente desea eliminar el usuario principal activo %1 de este vehículo? En\nese caso se perderán sus ajustes personales memorizados en el vehículo y se\ncargará el usuario invitado. El estado del usuario principal se mantiene.", fi_FI="Haluatko varmasti poistaa aktiivisen pääkäyttäjän %1 tästä autosta? Samalla\ntallentamasi yksilölliset asetukset häviävät ja vieraskäyttäjä latautuu. Pääkäyttäjän\nasema säilyy.", fr_FR="Souhaitez-vous vraiment supprimer de ce véhicule l'utilisateur principal actif\n%1? Tous vos réglages personnels mémorisés dans le véhicule seront ainsi\nperdus et le profil utilisateur invité sera chargé. Le statut d'utilisateur principal\nreste conservé.", hr_HR="Želite li aktivnog glavnog korisnika %1 uistinu ukloniti iz ovog vozila? Tako će\nse u vozilu izgubiti vaše pohranjene individualne postavke i učitat će se gost\nkorisnik. Status glavnog korisnika ostaje sačuvan.", hu_HU="Biztosan el szeretnéd távolítani az aktív %1 főfelhasználót ebből a járműből?\nA járműben mentett egyéni beállításaid ekkor elvesznek, és a vendégfelhasználó\ntöltődik be. A főfelhasználói státusz továbbra is megmarad.", it_IT="Eliminare l'utente principale attivo %1 da questa vettura? In questo modo le\nimpostazioni individuali memorizzate nella vettura andranno perse e verrà caricato\nl'utente ospite. Lo stato di utente principale rimane invariato.", nl_NL="Wil je de actieve hoofdgebruiker %1 echt uit dit voertuig verwijderen? Dan\ngaan je opgeslagen individuele instellingen in het voertuig verloren en wordt de\ngastgebruiker geladen. De hoofdgebruikerstatus blijft bestaan.", no_NO="Er du sikker på at du vil fjerne den aktive hovedbrukeren %1 fra denne bilen?\nDa går de lagrede personlige innstillingene dine tapt, og gjestebrukeren lastes inn.\nStatusen som hovedbruker beholdes.", pl_PL="Czy na pewno chcesz usunąć aktywnego użytkownika głównego %1 z tego\npojazdu? Spowoduje to, że Twoje zapisane ustawienia indywidualne zostaną\nutracone i zostanie wczytany użytkownik-gość. Status użytkownika głównego\nzostanie zachowany.", pt_PT="Queres mesmo remover o utilizador principal ativo %1 deste veículo? Deste\nmodo os teus ajustes pessoais memorizados no veículo desaparecerão e será\ncarregado o utilizador convidado. O estado do utilizador principal mantém-se.", ro_RO="Doriţi într-adevăr să ştergeţi utilizatorul principal activ %1 din acest\nautovehicul? Astfel, setările individuale memorate în autovehicul se vor pierde şi se\nva încărca utilizatorul oaspete. Starea utilizatorului principal se păstrează.", ru_RU="Вы действительно хотите удалить активного основного пользователя %1 из\nэтого автомобиля? Это приведет к потере сохраненных вами индивидуальных\nнастроек и загрузке гостевого пользователя. Статус основного пользователя\nсохранится.", sk_SK="Skutočne chcete odstrániť aktívneho primárneho používateľa %1 z tohto\nvozidla? Tým sa vaše uložené individuálne nastavenia vo vozidle stratia a načíta sa\npoužívateľ typu hosť. Stav hlavného používateľa zostáva zachovaný.", sl_SI="Ali res želite aktivnega glavnega uporabnika %1 odstraniti iz tega vozila? S\ntem boste izgubili shranjene individualne nastavitve v vozilu in naložen bo gostujoči\nuporabnik. Status glavnega uporabnika se ohrani.", sr_RS="Da li zaista želite da uklonite aktivnog glavnog korisnika %1 iz ovog vozila?\nTime će biti izgubljena vaša sačuvana individualna podešavanja i učitan gostujući\nkorisnik. Status glavnog korisnika ostaje.", sv_SE="Vill du verkligen ta bort den aktiva huvudanvändaren %1 från detta fordon? I\nså fall går dina sparade individuella inställningar i fordonet förlorade och\ngästanvändaren laddas. Huvudanvändarens status blir kvar.", tr_TR="Aktif ana kullanıcıyı %1 bu araçtan gerçekten kaldırmak istiyor musun?\nBöylece araçtaki kaydedilmiş kişisel ayarların kaybolur ve misafir kullanıcı yüklenir.\nAna kullanıcı statüsü aynı kalır.", uk_UA="Ви дійсно хочете видалити активного основного користувача %1 з цього\nавтомобіля? Ваші збережені індивідуальні налаштування в транспортному засобі\nбудуть втрачені, а гостьовий користувач буде завантажений. Статус основного\nкористувача залишиться.")
texttool_globals_dialog_message___delete_user_warning_active_user = TextObject(bs_BA="Da li zaista želite ukloniti aktivnog korisnika %1 iz ovog vozila? Na taj način će\nbiti izgubljene Vaše memorisane individualne postavke i učitava se korisnik gost.", cs_CZ="Chcete opravdu odstranit aktivního uživatele %1 z tohoto vozidla? Tím se\nvšechna Vaše uložená individuální nastavení ztratí a načte se uživatel Host.", da_DK="Vil du virkelig fjerne den aktive bruger %1 fra denne bil? Dermed går dine\ngemte individuelle indstillinger tabt, og gæstebrugeren indlæses.", de_DE="Möchtest du den aktiven Nutzer %1 wirklich aus diesem Fahrzeug entfernen?\nDamit gehen deine gespeicherten individuellen Einstellungen verloren und der\nGastnutzer wird geladen.", el_GR="Θέλετε σίγουρα να αφαιρέσετε τον ενεργό χρήστη %1 από αυτό το όχημα; Έτσι\nθα χαθούν οι αποθηκευμένες σας προσωπικές ρυθμίσεις και θα γίνει φόρτωση του\nχρήστη επισκέπτη.", en_GB="Do you really want to delete the active user %1 from this vehicle? Your stored\nindividual settings will be lost and the guest account will be loaded.", es_ES="¿Realmente desea eliminar el usuario activo %1 de este vehículo? En ese caso\nse perderán sus ajustes individuales memorizados y se cargará el usuario invitado.", fi_FI="Haluatko varmasti poistaa aktiivisen käyttäjän %1 tästä autosta? Samalla\ntallentamasi yksilölliset asetukset häviävät ja vieraskäyttäjä latautuu.", fr_FR="Souhaitez-vous vraiment supprimer de ce véhicule l'utilisateur actif %1? Tous\nvos réglages personnels mémorisés seront ainsi perdus et le profil utilisateur invité\nsera chargé.", hr_HR="Želite li aktivnog korisnika %1 stvarno ukloniti iz ovog vozila? Time će se\nizgubiti vaše pohranjene individualne postavke i učitat će se gost-korisnik.", hu_HU="Biztosan el szeretnéd távolítani az aktív felhasználót %1 ebből a járműből? A\nmentett egyéni beállításaid ekkor elvesznek, és a vendégfelhasználó töltődik be.", it_IT="Eliminare l'utente attivo %1 da questa vettura? In questo modo le\nimpostazioni individuali memorizzate andranno perse e verrà caricato l'utente\nospite.", nl_NL="Wil je de actieve gebruiker %1 echt uit dit voertuig verwijderen? Hiermee gaan\nde opgeslagen individuele instellingen verloren en wordt de gastgebruiker geladen.", no_NO="Er du sikker på at du vil fjerne den aktive brukeren %1 fra denne bilen? Da går\nde lagrede personlige innstillingene dine tapt, og gjestebrukeren lastes inn.", pl_PL="Czy na pewno chcesz usunąć aktywnego użytkownika %1 z tego pojazdu?\nSpowoduje to, że zapisane ustawienia indywidualne zostaną utracone i zostanie\nwczytany użytkownik-gość.", pt_PT="Queres mesmo remover o utilizador ativo %1 deste veículo? Desta forma, os\nteus ajustes individuais memorizados perder-se-ão e será carregado o utilizador\nconvidado.", ro_RO="Doriţi să ştergeţi într-adevăr utilizatorul activ %1 din acest autovehicul?\nAstfel, setările individuale memorate se vor pierde şi se va încărca utilizatorul\noaspete.", ru_RU="Вы действительно хотите удалить активного пользователя %1 из этого\nавтомобиля? Это приведет к потере сохраненных Вами индивидуальных\nнастроек и загрузке гостевого пользователя.", sk_SK="Skutočne chcete z tohto vozidla odstrániť aktívneho používateľa %1? Vaše\nuložené individuálne nastavenia sa potom stratia a načíta sa používateľ typu Hosť.", sl_SI="Ali res želite aktivnega uporabnika %1 odstraniti iz tega vozila? S tem boste\nizgubili shranjene individualne nastavitve in naložen bo gostujoči uporabnik.", sr_RS="Da li zaista želite da uklonite aktivnog korisnika %1 iz ovog vozila? Na taj način\nće biti izgubljena vaša sačuvana individualna podešavanja, korisnik gost će biti\nučitan.", sv_SE="Vill du verkligen ta bort den aktiva användaren %1 ur detta fordon? Dina\nsparade individuella inställningar går då förlorade och gästanvändaren laddas.", tr_TR="Aktif kullanıcıyı %1 bu araçtan gerçekten kaldırmak istiyor musun? Böylece\nkaydedilmiş kişisel ayarların kaybolur ve misafir kullanıcı yüklenir.", uk_UA="Дійсно видалити активного користувача %1 з цього автомобіля? У такому\nразі збережені індивідуальні настройки буде втрачено й буде завантажено\nкористувача-гостя.")
texttool_globals_dialog_message___delete_user_warning_user = TextObject(bs_BA="Da li zaista želite ukloniti korisnika %1 iz ovog vozila? Na taj način će biti\nizgubljene Vaše memorisane individualne postavke.", cs_CZ="Chcete opravdu odstranit uživatele %1 z tohoto vozidla? Tím se uložená\nindividuální nastavení ztratí.", da_DK="Vil du virkelig fjerne brugeren %1 fra denne bil? Dermed går de gemte\nindividuelle indstillinger tabt.", de_DE="Möchtest du den Nutzer %1 wirklich aus diesem Fahrzeug entfernen?\nDamit gehen die gespeicherten individuellen Einstellungen verloren.", el_GR="Θέλετε σίγουρα να αφαιρέσετε τον ενεργό χρήστη %1 από αυτό το όχημα; Έτσι\nθα χαθούν οι αποθηκευμένες σας προσωπικές ρυθμίσεις.", en_GB="Do you really want to delete the user %1 from this vehicle? The stored\nindividual settings will be lost.", es_ES="¿Realmente desea eliminar el usuario %1 de este vehículo? En ese caso se\nperderán los ajustes individuales memorizados.", fi_FI="Haluatko varmasti poistaa käyttäjän %1 tästä autosta? Samalla tallennetut\nyksilölliset asetukset häviävät.", fr_FR="Souhaitez-vous vraiment supprimer de ce véhicule l'utilisateur %1? Tous vos\nréglages personnels mémorisés seront ainsi perdus.", hr_HR="Želite li korisnika %1 stvarno ukloniti iz ovog vozila? Time će se izgubiti\npohranjene individualne postavke.", hu_HU="Biztosan el szeretnéd távolítani a felhasználót %1 ebből a járműből? A\nmentett egyéni beállítások ekkor elvesznek.", it_IT="Eliminare l'utente %1 da questa vettura? In questo modo le impostazioni\nindividuali memorizzate andranno perse.", nl_NL="Wil je gebruiker %1 uit dit voertuig verwijderen? Hiermee gaan de opgeslagen\nindividuele instellingen verloren.", no_NO="Er du sikker på at du vil fjerne brukeren %1 fra denne bilen? Da går de lagrede\npersonlige innstillingene tapt.", pl_PL="Czy na pewno chcesz usunąć aktywnego użytkownika %1 z tego pojazdu?\nSpowoduje to, że zapisane ustawienia indywidualne zostaną utracone.", pt_PT="Queres mesmo remover o utilizador %1 deste veículo? Desta forma, os ajustes\nindividuais memorizados perder-se-ão.", ro_RO="Doriţi să ştergeţi într-adevăr utilizatorul activ %1 din acest autovehicul?\nAstfel, setările individuale memorate se vor pierde.", ru_RU="Вы действительно хотите удалить пользователя %1 из этого автомобиля?\nЭто приведет к потере сохраненных индивидуальных настроек.", sk_SK="Skutočne chcete z tohto vozidla odstrániť používateľa %1? Uložené\nindividuálne nastavenia sa potom stratia.", sl_SI="Ali res želite uporabnika %1 odstraniti iz tega vozila? S tem boste izgubili\nshranjene individualne nastavitve.", sr_RS="Da li zaista želite da uklonite korisnika %1 iz ovog vozila? Na taj način će biti\nizgubljena vaša sačuvana individualna podešavanja.", sv_SE="Vill du verkligen ta bort användaren %1 ur detta fordon? Dina sparade\nindividuella inställningar går då förlorade.", tr_TR="Kullanıcıyı %1 bu araçtan gerçekten kaldırmak istiyor musun? Böylece\nkaydedilmiş kişisel ayarlar kaybolur.", uk_UA="Дійсно видалити активного користувача %1 з цього автомобіля? У такому\nразі збережені індивідуальні настройки буде втрачено.")
texttool_globals_dialog_message___personalize_user_dialog_message = TextObject(bs_BA="Personalizirajte Vašeg korisnika tek kada Vašeg korisnika budete\nhtjeli zaštititi pomoću PIN-a.", cs_CZ="Pokud chcete svého uživatele chránit pomocí kódu PIN, nejprve si ho prosím\npřizpůsobte.", da_DK="Individualiser først din bruger, hvis du gerne vil beskytte din bruger med en\npinkode.", de_DE="Bitte personalisiere zuerst deinen Nutzer, wenn du deinen Nutzer mit einer PIN\nschützen möchtest.", el_GR="Εξατομικεύστε πρώτα τον λογαριασμό χρήστη σας, εάν θέλετε να τον προστατεύσετε\nμε PIN.", en_GB="Please customise your user first if you wish to protect your user with a PIN.", es_ES="Personalice primero su usuario\nsi desea protegerlo con un PIN.", fi_FI="Yksilöi ensin käyttäjäprofiilisi, jos haluat suojata käyttäjätilisi PIN-koodilla.", fr_FR="Veuillez d'abord personnaliser votre profil utilisateur si vous souhaitez le protéger\navec un code PIN.", hr_HR="Prvo personalizirajte svoj korisnički račun ako ga želite zaštititi PIN-om.", hu_HU="Először végezd el a felhasználód személyre szabását, ha PIN-kóddal szeretnéd\nvédeni a felhasználódat.", it_IT="Prima personalizzare l'utente, se si desidera proteggerlo con un PIN.", nl_NL="Personaliseer eerst je gebruiker als je deze met een pincode wilt beschermen.", no_NO="Hvis du vil beskytte brukeren din med en PIN-kode, må du først tilpasse brukeren.", pl_PL="Jeśli użytkownik ma być chroniony kodem PIN, musisz go najpierw spersonalizować.", pt_PT="Por favor, personaliza primeiro o teu utilizador caso desejes proteger o teu\nutilizador com um PIN.", ro_RO="Vă rugăm să vă personalizaţi întâi utilizatorul, dacă doriţi să vă protejaţi utilizatorul\ncu un PIN.", ru_RU="Если вы хотите защитить своего пользователя с помощью PIN-кода, сначала\nперсонализируйте его.", sk_SK="Prosím, najskôr personalizujte vášho používateľa, aby ste ho chránili pomocou PIN\nkódu.", sl_SI="Najprej personalizirajte uporabnika, če ga želite zaščititi s PIN-kodo.", sr_RS="Personalizaciju vašeg korisnika izvršite tek kada vašeg korisnika\nželite da zaštitite pomoću PIN-a.", sv_SE="Anpassa först din användare om du vill skydda användaren med en PIN-kod.", tr_TR="Kullanıcını bir PIN ile korumak istiyorsan lütfen önce kullanıcını kişiselleştir.", uk_UA="Якщо ви хочете захистити свого користувача за допомогою PIN-коду, будь ласка,\nспочатку персоналізуйте його.")
texttool_globals_dialog_message___primary_user_reset_warning_dialog_with_logbook = TextObject(bs_BA="Želite li ukloniti glavnog korisnika za ovo vozilo? Na taj način svi korisnici gube\npripadajuća ovlaštenja. Deaktivira se usluga „Online dnevnik vožnje“.", cs_CZ="Chcete odstranit hlavního uživatele pro toto vozidlo? Tím všichni další uživatelé\nztratí svá příslušná oprávnění. Služba \"Online kniha jízd\" se deaktivuje.", da_DK="Vil du fjerne den primære bruger for denne bil? Dermed mister alle brugere deres\ntilhørende beføjelser. Tjenesten \"Onlinekørebog\" deaktiveres.", de_DE="Möchtest du den Hauptnutzer für dieses Fahrzeug entfernen? Damit verlieren alle\nNutzer ihre zugehörigen Berechtigungen. Der Dienst „Online-Fahrtenbuch“ wird\ndeaktiviert.", el_GR="Θέλετε να αφαιρέσετε τον βασικό χρήστη για αυτό το όχημα; Έτσι θα χάσουν όλοι οι\nχρήστες τις αντίστοιχες εξουσιοδοτήσεις τους. Η υπηρεσία \"Online ημερολόγιο\nδιαδρομών\" θα απενεργοποιηθεί.", en_GB="Would you like to remove the key user for this vehicle? All users will lose their\ncorresponding authorisations. The online logbook service will be deactivated.", es_ES="¿Desea eliminar el usuario principal de este vehículo? En ese caso todos los usuarios\nperderán sus permisos asociados. El servicio \"Registro de viajes online\"se\ndesactivará.", fi_FI="Haluatko poistaa tämän auton pääkäyttäjän? Samalla kaikkien käyttäjien asiaan\nliittyvät oikeudet häviävät. Palvelu \"online-ajopäiväkirja\" deaktivoidaan.", fr_FR="Souhaitez-vous supprimer l'utilisateur principal de ce véhicule? Tous les utilisateurs\nperdent ainsi leurs autorisations correspondantes. Le service «Carnet de route en\nligne» sera désactivé.", hr_HR="Želite li ukloniti glavnog korisnika za ovo vozilo? Tako svi korisnici gube svoja\npripadajuća ovlaštenja. Usluga \"Online knjiga vožnji\" se deaktivira.", hu_HU="El szeretnéd távolítani ennek a járműnek a főfelhasználóját? Ezzel az összes\nfelhasználó elveszíti a megfelelő jogosultságait. Az „Online\nútnyilvántartás”szolgáltatás kikapcsolódik.", it_IT="Eliminare l'utente principale per questa vettura? In questo modo tutti gli utenti\nperdono le relative autorizzazioni. Il servizio \"Giornale di bordo online\" viene\ndisattivato.", nl_NL="Wil je de hoofdgebruiker van dit voertuig verwijderen? Hiermee verliezen alle\ngebruikers hun autorisaties. De dienst \"online rittenboek\" wordt gedeactiveerd.", no_NO="Vil du fjerne hovedbrukeren for denne bilen? Da vil alle brukerne miste sine\nrettigheter. Tjenesten Online-kjørebok blir deaktivert.", pl_PL="Czy chcesz usunąć użytkownika głównego tego pojazdu? Spowoduje to utratę\nuprawnień przez wszystkich użytkowników. Usługa „Książka przejazdów online”\nzostanie wyłączona.", pt_PT="Queres remover o utilizador principal deste veículo? Desta forma, todos os\nutilizadores perdem as suas respetivas autorizações. O serviço \"Livro de registos de\nviagem online\" será desativado.", ro_RO="Doriţi să eliminaţi utilizatorul principal pentru acest autovehicul? Astfel, toţi\nutilizatorii îşi pierd drepturile aferente. Serviciul \"Foaie de parcurs online\" este\ndezactivat.", ru_RU="Хотите удалить основного пользователя для этого автомобиля? В результате все\nпользователи потеряют соответствующие права доступа. Служба «Онлайн\nбортовой журнал» будет отключена.", sk_SK="Chcete odstrániť hlavného používateľa tohto vozidla? To znamená, že všetci\npoužívatelia stratia svoje priradené oprávnenia. Služba „Online kniha jázd“ sa\ndeaktivuje.", sl_SI="Ali želite odstraniti glavnega uporabnika tega vozila? S tem vsi uporabniki izgubijo\npripadajoča pooblastila. Storitev \"Spletni dnevnik voženj\" bo deaktivirana.", sr_RS="Da li želite da uklonite glavnog korisnika za ovo vozilo? Na taj način svi korisnici\ngube svoja pripadajuća ovlašćenja. Usluga „Onlajn knjižica vožnji“ se deaktivira.", sv_SE="Vill du ta bort huvudanvändaren för detta fordon? Då förlorar alla användare sina\ntillhörande behörigheter. Tjänsten ”Körjournal online” avaktiveras.", tr_TR="Bu araç için ana kullanıcıyı kaldırmak istiyor musun? Böylece, tüm kullanıcılar ilişkili\nyetkilerini kaybederler. \"Çevrimiçi seyir defteri\" hizmeti devre dışı bırakılır.", uk_UA="Бажаєте видалити основного користувача для цього автомобіля? В результаті всі\nкористувачі втратять відповідні права доступу. Службу «Онлайновий журнал\nпоїздок» буде вимкнено.")
texttool_globals_dialog_message___primary_user_reset_warning_dialog_with_privacy_and_logbook = TextObject(bs_BA="Mobilni podaci su deaktivirani. Uklanjanjem glavnog korisnika svi korisnici gube\npripadajuća ovlaštenja. Usluga „Online dnevnik vožnji” će biti deaktivirana.\nUspostavite vezu sa internetom za završetak postupka.", cs_CZ="Mobilní data jsou deaktivovaná. Odstraněním hlavního uživatele ztratí všichni\nuživatelé svá příslušná oprávnění. Služba „Online kniha jízd“ se deaktivuje. Vytvořte\npřipojení k internetu, abyste mohli postup dokončit.", da_DK="Mobildata deaktiveret. Hvis du fjerner den primære bruger, mister alle brugere\nderes tilhørende beføjelser. Tjenesten \"Onlinekørebog\" deaktiveres. Opret\ninternetforbindelse for at afslutte processen.", de_DE="Mobile Daten deaktiviert. Mit dem Entfernen des Hauptnutzers verlieren alle Nutzer\nihre zugehörigen Berechtigungen. Der Dienst „Online-Fahrtenbuch“ wird\ndeaktiviert. Stelle eine Internetverbindung her, um den Vorgang abzuschließen.", el_GR="Τα δεδομένα κινητής τηλεφωνίας είναι απενεργοποιημένα. Με την αφαίρεση του\nβασικού χρήστη θα χάσουν όλοι οι χρήστες τις αντίστοιχες εξουσιοδοτήσεις τους. Η\nυπηρεσία „Online ημερολόγιο διαδρομών“ θα απενεργοποιηθεί. Δημιουργήστε μια\nσύνδεση με το διαδίκτυο για να ολοκληρώσετε τη διαδικασία.", en_GB="Mobile data deactivated. All users will lose their corresponding authorisations\nwhen the key user is removed. The online logbook service will be deactivated.\nPlease establish an Internet connection to complete the process.", es_ES="Datos móviles desactivados. Si elimina el usuario principal, todos los usuarios\nperderán sus permisos asociados. El servicio \"Registro de viajes online\" se\ndesactivará. Conéctese a Internet para finalizar el proceso.", fi_FI="Mobiilidata deaktivoitu. Kun pääkäyttäjä poistetaan, kaikkien käyttäjien asiaan\nliittyvät oikeudet häviävät. Online-ajopäiväkirja-palvelu deaktivoidaan. Muodosta\ninternetyhteys suorittaaksesi menettelyn loppuun.", fr_FR="Données mobiles désactivées. Lors de la suppression de l'utilisateur principal, tous\nles utilisateurs perdent leurs autorisations correspondantes. Le service «Carnet de\nroute en ligne» sera désactivé. Établissez une connexion Internet pour terminer la\nprocédure.", hr_HR="Mobilni podaci deaktivirani. S uklanjanjem glavnog korisnika svi korisnici gube svoja\npripadajuća odobrenja. Usluga \"Online knjiga vožnje\" se deaktivira. Uspostavite\ninternetsku vezu kako biste završili postupak.", hu_HU="Mobil adatok kikapcsolva. A főfelhasználó eltávolításával az összes felhasználó\nelveszíti a megfelelő jogosultságait. Az „Online útnyilvántartás”szolgáltatás\nkikapcsolódik. A folyamat befejezéséhez csatlakozz az internethez.", it_IT="Dati mobili disattivati. Eliminando l'utente principale, tutti gli utenti perdono le\nrelative autorizzazioni. Il servizio \"Giornale di bordo online\" viene disattivato.\nCollegarsi a internet per completare la procedura.", nl_NL="Mobiele data gedeactiveerd. Met het verwijderen van de hoofdgebruiker verliezen\nalle gebruikers hun bijbehorende autorisaties. De dienst \"online rittenboek\" wordt\ngedeactiveerd. Breng internetverbinding tot stand om de bewerking af te sluiten.", no_NO="Mobildata er deaktivert. Hvis du fjerner hovedbrukeren, mister alle brukere sine\nrettigheter. Tjenesten «Online-kjørebok» blir deaktivert. Opprett\ninternettforbindelse for å fullføre prosessen.", pl_PL="Dane mobilne wyłączone. Usunięcie użytkownika głównego spowoduje utratę\nuprawnień wszystkich użytkowników. Usługa „Książka przejazdów online” zostanie\nwyłączona. Aby zakończyć proces, nawiąż połączenie z Internetem.", pt_PT="Dados móveis desativados. Com a eliminação do utilizador principal, desaparecem\ntodos os utilizadores e as suas respetivas permissões. O serviço “Livro de registos\nde viagem” será desativado. Estabelece uma ligação à Internet para concluir o\nprocedimento.", ro_RO="Date mobile dezactivate. Prin eliminarea utilizatorului principal, toţi utilizatorii îşi\npierd drepturile aferente. Se dezactivează serviciul \"Foaie de parcurs online\".\nRealizaţi conexiunea la Internet, pentru a finaliza procesul.", ru_RU="Мобильные данные отключены. При удалении основного пользователя все\nпользователи теряют связанные с ним полномочия. Сервис «Онлайн бортовой\nжурнал» деактивирован. Для завершения процесса установите подключение к\nИнтернету.", sk_SK="Mobilné dáta deaktivované. Po odstránení hlavného používateľa stratia všetci\npoužívatelia svoje priradené oprávnenia. Služba „Online kniha jázd“ sa deaktivuje.\nNa ukončenie procesu vytvorte internetové pripojenie.", sl_SI="Mobilni podatki deaktivirani. Z odstranitvijo glavnega uporabnika vsi uporabniki\nizgubijo pripadajoča pooblastila. Storitev \"Spletni dnevnik voženj\" bo deaktivirana.\nZa zaključek postopka vzpostavite internetno povezavo.", sr_RS="Mobilni podaci su deaktivirani. Uklanjanjem glavnog korisnika svi korisnici gube\npripadajuća ovlašćenja. Usluga „Onlajn knjižica vožnji” biće deaktivirana.\nUspostavite vezu sa internetom da biste završili postupak.", sv_SE="Mobildata avaktiverad. När du tar bort huvudanvändaren förlorar alla användare\nsina tillhörande behörigheter. Tjänsten ”Körjournal online” avaktiveras. Upprätta en\ninternetanslutning för att slutföra processen.", tr_TR="Mobil veriler devre dışı bırakıldı. Ana kullanıcının kaldırılması ile birlikte tüm\nkullanıcılar ilişkili yetkilerini kaybederler. \"Çevrimiçi seyir defteri\" hizmeti devre dışı\nbırakılır. İşlemi tamamlamak için, bir internet bağlantısı oluştur.", uk_UA="Мобільні дані вимкнено. При видаленні основного користувача всі користувачі\nвтрачають пов'язані з ним повноваження. Служба «Онлайн журнал поїздок»\nдезактивована. Для завершення процесу встановіть підключення до Інтернету.")
texttool_globals_dialog_message___primary_user_reset_warning_dialog_with_privacy_without_logbook = TextObject(bs_BA="Mobilni podaci su deaktivirani. Uklanjanjem glavnog korisnika svi korisnici gube\npripadajuća ovlaštenja. Uspostavite vezu sa internetom za završetak postupka.", cs_CZ="Mobilní data deaktivována. Odstraněním hlavního uživatele ztratí všichni uživatelé\nsvá příslušná oprávnění. Vytvořte připojení k internetu, abyste mohli postup\ndokončit.", da_DK="Mobildata deaktiveret. Hvis du fjerner den primære bruger, mister alle brugere\nderes tilhørende beføjelser. Opret internetforbindelse for at afslutte processen.", de_DE="Mobile Daten deaktiviert. Mit dem Entfernen des Hauptnutzers verlieren alle Nutzer\nihre zugehörigen Berechtigungen. Stelle eine Internetverbindung her, um den\nVorgang abzuschließen.", el_GR="Τα δεδομένα κινητής τηλεφωνίας είναι απενεργοποιημένα. Με την αφαίρεση του\nκύριου χρήστη θα χάσουν όλοι οι χρήστες τις αντίστοιχες εξουσιοδοτήσεις τους.\nΔημιουργήστε μια σύνδεση με το διαδίκτυο για να ολοκληρώσετε τη διαδικασία.", en_GB="Mobile data deactivated. All users will lose their corresponding authorisations\nwhen the key user is removed. Establish an Internet connection to complete the\nprocess.", es_ES="Datos móviles desactivados. Si elimina el usuario principal, todos los usuarios\nperderán sus permisos asociados. Conéctese a Internet para finalizar el proceso.", fi_FI="Mobiilidata deaktivoitu. Kun pääkäyttäjä poistetaan, kaikkien käyttäjien asiaan\nliittyvät oikeudet häviävät. Muodosta internetyhteys suorittaaksesi menettelyn\nloppuun.", fr_FR="Données mobiles désactivées. Lors de la suppression de l'utilisateur principal, tous\nles utilisateurs perdent leurs autorisations correspondantes. Établissez une\nconnexion Internet pour terminer la procédure.", hr_HR="Mobilni podaci deaktivirani. S uklanjanjem glavnog korisnika svi korisnici gube svoja\npripadajuća odobrenja. Uspostavite internetsku vezu kako biste završili postupak.", hu_HU="Mobiladatok kikapcsolva. A főfelhasználó eltávolításával az összes felhasználó\nelveszíti a megfelelő jogosultságait. A folyamat befejezéséhez csatlakozz az\ninternethez.", it_IT="Dati mobili disattivati. Eliminando l'utente principale, tutti gli utenti perdono le\nrelative autorizzazioni. Collegarsi a internet per completare la procedura.", nl_NL="Mobiele data gedeactiveerd. Met het verwijderen van de hoofdgebruiker verliezen\nalle gebruikers hun bijbehorende autorisaties. Breng een internetverbinding tot\nstand om de bewerking af te sluiten.", no_NO="Mobildata er deaktivert. Hvis du fjerner hovedbrukeren, mister alle brukere sine\nrettigheter. Opprett internettforbindelse for å fullføre prosessen.", pl_PL="Mobilne dane wyłączone. Usunięcie użytkownika głównego spowoduje utratę\nuprawnień przez wszystkich użytkowników. Aby zakończyć proces, nawiąż\npołączenie z Internetem.", pt_PT="Dados móveis desativados. Com a eliminação do utilizador principal, desaparecem\ntodos os utilizadores e as suas respetivas permissões. O serviço “Livro de registos\nde viagem” será desativado. Estabelece uma ligação à Internet para concluir o\nprocedimento.", ro_RO="Date mobile dezactivate. Prin eliminarea utilizatorului principal, toţi utilizatorii îşi\npierd drepturile aferente. Realizaţi conexiunea la Internet, pentru a finaliza\nprocesul.", ru_RU="Мобильные данные отключены. При удалении основного пользователя все\nпользователи теряют связанные с ним полномочия. Для завершения процесса\nустановите подключение к Интернету.", sk_SK="Mobilné dáta deaktivované. Po odstránení hlavného používateľa stratia všetci\npoužívatelia svoje priradené oprávnenia. Na ukončenie procesu vytvorte internetové\npripojenie.", sl_SI="Mobilni podatki deaktivirani. Z odstranitvijo glavnega uporabnika vsi uporabniki\nizgubijo pripadajoča pooblastila. Za zaključek postopka vzpostavite internetno\npovezavo.", sr_RS="Mobilni podaci su deaktivirani. Uklanjanjem glavnog korisnika svi korisnici gube\npripadajuća ovlašćenja. Uspostavite vezu sa internetom da biste završili postupak.", sv_SE="Mobildata avaktiverad. När du tar bort huvudanvändaren förlorar alla användare\nsina tillhörande behörigheter. Upprätta en internetanslutning för att slutföra\nprocessen.", tr_TR="Mobil veriler devre dışı bırakıldı. Ana kullanıcının kaldırılması ile birlikte tüm\nkullanıcılar ilişkili yetkilerini kaybederler. İşlemi tamamlamak için, bir internet\nbağlantısı oluştur.", uk_UA="Мобільні дані вимкнено. При видаленні основного користувача всі користувачі\nвтрачають пов'язані з ним повноваження. Для завершення процесу встановіть\nпідключення до Інтернету.")
texttool_globals_dialog_message___primary_user_reset_warning_dialog_without_logbook = TextObject(bs_BA="Želite li ukloniti glavnog korisnika za ovo vozilo? Na taj način svi korisnici gube\npripadajuća ovlaštenja.", cs_CZ="Chcete odstranit hlavního uživatele pro toto vozidlo? Tím všichni další uživatelé\nztratí svá příslušná oprávnění.", da_DK="Vil du fjerne den primære bruger for denne bil? Dermed mister alle brugere deres\ntilhørende beføjelser.", de_DE="Möchtest du den Hauptnutzer für dieses Fahrzeug entfernen? Damit verlieren alle\nNutzer ihre zugehörigen Berechtigungen.", el_GR="Θέλετε να αφαιρέσετε τον βασικό χρήστη για αυτό το όχημα; Έτσι θα χάσουν όλοι οι\nχρήστες τις αντίστοιχες εξουσιοδοτήσεις τους.", en_GB="Would you like to remove the key user for this vehicle? All users will lose their\ncorresponding authorisations.", es_ES="¿Desea eliminar el usuario principal de este vehículo? En ese caso todos los usuarios\nperderán sus permisos asociados.", fi_FI="Haluatko poistaa tämän auton pääkäyttäjän? Samalla kaikkien käyttäjien asiaan\nliittyvät oikeudet häviävät.", fr_FR="Souhaitez-vous supprimer l'utilisateur principal de ce véhicule? Tous les utilisateurs\nperdent ainsi leurs autorisations correspondantes.", hr_HR="Želite li ukloniti glavnog korisnika za ovo vozilo? Tako svi korisnici gube svoja\npripadajuća ovlaštenja.", hu_HU="El szeretnéd távolítani ennek a járműnek a főfelhasználóját? Ezzel az összes\nfelhasználó elveszíti a megfelelő jogosultságait.", it_IT="Eliminare l'utente principale per questa vettura? In questo modo tutti gli utenti\nperdono le relative autorizzazioni.", nl_NL="Wil je de hoofdgebruiker van dit voertuig verwijderen? Hiermee verliezen alle\ngebruikers hun autorisaties.", no_NO="Vil du fjerne hovedbrukeren for denne bilen? Da vil alle brukerne miste sine\nrettigheter.", pl_PL="Czy chcesz usunąć głównego użytkownika tego pojazdu? Spowoduje to utratę\nuprawnień wszystkich użytkowników.", pt_PT="Queres remover o utilizador principal deste veículo? Desta forma, todos os\nutilizadores perdem as suas respetivas autorizações.", ro_RO="Doriţi să eliminaţi utilizatorul principal pentru acest autovehicul? Astfel, toţi\nutilizatorii îşi pierd drepturile aferente.", ru_RU="Хотите удалить основного пользователя для этого автомобиля? В результате все\nпользователи потеряют соответствующие права доступа.", sk_SK="Chcete odstrániť hlavného používateľa tohto vozidla? To znamená, že všetci\npoužívatelia stratia svoje priradené oprávnenia.", sl_SI="Ali želite odstraniti glavnega uporabnika tega vozila? S tem vsi uporabniki izgubijo\npripadajoča pooblastila.", sr_RS="Da li želite da uklonite glavnog korisnika za ovo vozilo? Na taj način svi korisnici\ngube pripadajuća ovlašćenja.", sv_SE="Vill du ta bort huvudanvändaren för detta fordon? Då förlorar alla användare sina\ntillhörande behörigheter.", tr_TR="Bu araç için ana kullanıcıyı kaldırmak istiyor musun? Böylece, tüm kullanıcılar ilişkili\nyetkilerini kaybederler.", uk_UA="Бажаєте видалити основного користувача для цього автомобіля? В результаті всі\nкористувачі втратять відповідні права доступу.")
texttool_globals_dialog_message___switch_user_to_guest_warning = TextObject(bs_BA="Da li zaista želite promijeniti korisnika? Sistemske postavke i postavke sistema\npomoći za vozača se mogu promijeniti.", cs_CZ="Chcete opravdu přepnout uživatele? Nastavení systému a asistence řidiče se mohou\nzměnit.", da_DK="Vil du virkelig skifte bruger? System- og førerassistentindstillinger kan ændre sig.", de_DE="Willst du den Nutzer wirklich wechseln? System- und Fahrerassistenzeinstellungen\nkönnen sich ändern.", el_GR="Θέλετε σίγουρα να αλλάξετε τον χρήστη; Ενδέχεται να αλλάξουν οι ρυθμίσεις\nσυστήματος και υποβοήθησης οδηγού.", en_GB="Do you really want to change user? System and driver assist settings may change.", es_ES="¿Realmente desea cambiar de usuario? Los ajustes del sistema y de la asistencia al\nconductor pueden cambiar.", fi_FI="Haluatko varmasti vaihtaa käyttäjää? Järjestelmien ja kuljettajan apujärjestelmien\nasetukset saattavat muuttua.", fr_FR="Souhaitez-vous vraiment changer d'utilisateur? Les réglages du système et des\naides au conducteur peuvent être différents.", hr_HR="Želite li uistinu promijeniti korisnika? Sistemske postavke i postavke potpore za\nvozača mogu se promijeniti.", hu_HU="Valóban felhasználót szeretnél váltani? A rendszer és a vezetőasszisztensek\nbeállításai megváltozhatnak.", it_IT="Cambiare utente? Le impostazioni dei sistemi e dell'assistenza al conducente\npotrebbero cambiare.", nl_NL="Wil je de gebruiker echt vervangen? Systeem- en\nbestuurdershulpinstellingen kunnen veranderen.", no_NO="Er du sikker på at du vil bytte bruker? Systeminnstillinger og innstillinger for\nførerassistentsystemer kan bli endret.", pl_PL="Czy na pewno chcesz zmienić użytkownika? Ustawienia systemu i asysty kierowcy\nmogą ulec zmianie.", pt_PT="Desejas mesmo mudar de utilizador? É possível que os ajustes do sistema e do\ncondutor se alterem.", ro_RO="Doriţi într-adevăr să schimbaţi utilizatorul? Setările de sistem şi asistenţă a\nşoferului se pot modifica.", ru_RU="Вы действительно хотите сменить пользователя? Системные настройки и\nнастройки ассистирующих систем водителя могут измениться.", sk_SK="Skutočne chcete zmeniť používateľa? Nastavenia systému a asistencie\nvodiča sa môžu zmeniť.", sl_SI="Ali res želite zamenjati uporabnika? Sistemske nastavitve in nastavitve asistenčnih\nsistemov se lahko spremenijo.", sr_RS="Da li zaista želite da izmenite korisnika? Podešavanja sistema i asistencije za vozača\nmogu da se izmene.", sv_SE="Vill du verkligen växla användare? System- och förarassistansinställningar kan\nkomma att ändras.", tr_TR="Kullanıcıyı gerçekten değiştirmek istiyor musun? Sistem ve sürücü yardımı ayarları\ndeğişebilir.", uk_UA="Ви дійсно хочете змінити користувача? Настройки системи та настройки\nдопоміжних систем для водія можуть змінитися.")
texttool_globals_dialog_message___switch_user_to_temporary_user_warning = TextObject(bs_BA="Želite li preći na inkognito korisnika? Sistemske postavke i postavke sistema\nasistencije za vozača se mogu promijeniti. Podaci se neće sačuvati u ovom\nkorisniku.", cs_CZ="Chcete přepnout do anonymního režimu? Nastavení systému a asistence řidiče se\nmůže změnit. U tohoto uživatele nejsou ukládána data.", da_DK="Vil du skifte til inkognitobrugeren? System- og førerassistentindstillinger\nkan ændre sig. Der gemmes ikke data på denne bruger.", de_DE="Möchtest du zum Inkognito-Nutzer wechseln? System- und\nFahrassistenzeinstellungen können sich ändern. Daten werden in diesem Nutzer\nnicht gespeichert.", el_GR="Θέλετε να αλλάξετε στον ανώνυμο (incognito) χρήστη; Ενδέχεται να αλλάξουν\nρυθμίσεις συστήματος και υποβοήθησης οδηγού. Σε αυτόν τον λογαριασμό χρήστη\nδεν γίνεται αποθήκευση δεδομένων.", en_GB="Do you want to switch to a temporary user? System and driver assist settings may\nchange. Data is not saved for this user.", es_ES="¿Desea cambiar al usuario incógnito? Esto puede cambiar los ajustes del sistema\ny de la asistencia al conductor. Los datos no se guardan en dicho usuario.", fi_FI="Haluatko vaihtaa Tuntematon-käyttäjäprofiiliin? Järjestelmän ja kuljettajaa\navustavien järjestelmien asetukset voivat muuttua. Tietoja ei tallenneta tällä\nkäyttäjäprofiililla.", fr_FR="Souhaitez-vous passer au profil utilisateur incognito?\nLes réglages du système et des aides au conducteur peuvent être différents.\nLes données ne sont pas mémorisées dans ce profil utilisateur.", hr_HR="Želite li se prebaciti na inkognito korisnički račun? Sistemske postavke i postavke\npotpora za vozača mogu se promijeniti. Podaci se u ovom korisničkom računu neće\npohraniti.", hu_HU="Inkognitó felhasználóra szeretnél váltani? A rendszer és az asszisztensek beállításai\nmegváltozhatnak. Az adatok nem kerülnek mentésre ebben a felhasználóban.", it_IT="Si desidera passare all'utente in incognito? Le impostazioni dei sistemi e\ndell'assistenza al conducente potrebbero cambiare. I dati non vengono memorizzati\nin questo utente.", nl_NL="Wil je overschakelen op de incognito-gebruiker? De instellingen voor systeem- en\nbestuurdershulp kunnen veranderen. In deze gebruiker worden geen gegevens\nopgeslagen.", no_NO="Vil du bytte til inkognito-brukeren? Da kan systeminnstillinger og innstillinger for\nførerassistentsystemer bli endret. Det lagres ikke data for denne brukeren.", pl_PL="Czy chcesz przełączyć się na użytkownika Incognito? Ustawienia systemu i pomocy\nkierowcy mogą ulec zmianie. Dane tego użytkownika nie są zapisywane.", pt_PT="Queres mudar para o utilizador anónimo? Os ajustes do sistema e da assistência à\ncondução podem sofrer alterações. Os dados não serão memorizados neste\nutilizador.", ro_RO="Doriţi să comutaţi la utilizatorul Incognito? Se pot modifica setările sistemului şi de\nasistenţă a şoferului. Datele nu sunt memorate în acest utilizator.", ru_RU="Хотите переключиться на пользователя инкогнито? Настройки системы и\nсистемы помощи водителю могут измениться. Данные в этом пользователе не\nсохраняются.", sk_SK="Chcete zmenu na inkognito používateľa? Nastavenia systému a podporných\nsystémov sa môžu zmeniť. Dáta sa v tomto používateľovi neukladajú.", sl_SI="Ali želite preklopiti na inkognito uporabnika? Sistemske nastavitve in nastavitve\nasistenčnih sistemov se lahko spremenijo. Podatki se ne shranijo za tega\nuporabnika.", sr_RS="Da li želite da pređete na inkognito korisnika? Podešavanja sistema\ni asistencije za vožnju mogu da se izmene. Podaci se ne čuvaju u\novom korisniku.", sv_SE="Vill du växla till Inkognito-läget? System- och förarassistansinställningar kan\nändras. Data sparas inte på denna användare.", tr_TR="Gizli kullanıcıya geçiş yapmak istiyor musun? Sistem ve sürüş desteği ayarları\ndeğişebilir. Bu kullanıcı için veriler kaydedilmez.", uk_UA="Бажаєте переключитися на користувача інкогніто? Налаштування системи та\nдопомоги водієві можуть змінитися. Дані цього користувача не зберігаються.")
texttool_globals_dialog_message___switch_user_warning = TextObject(bs_BA="Želite li zaista prebaciti na korisnika %1? Postavke sistema i pomoći vozaču se\nmogu promijeniti.", cs_CZ="Opravdu chcete přepnout na uživatele %1? Nastavení systému a asistence\nřidiče se může změnit.", da_DK="Vil du virkelig skifte til brugeren %1? System- og førerassistentindstillinger\nkan ændre sig.", de_DE="Willst du zum Nutzer %1 wirklich wechseln? System- und\nFahrerassistenzeinstellungen können sich ändern.", el_GR="Θέλετε σίγουρα να αλλάξετε στον λογαριασμό χρήστη %1; Ενδέχεται να\nαλλάξουν οι ρυθμίσεις συστήματος και υποβοήθησης οδηγού.", en_GB="Do you really want to switch to user %1? System settings and driver assist\nsettings could change.", es_ES="¿Realmente desea cambiar al usuario %1? Los ajustes del sistema y de la\nasistencia al conductor pueden cambiar.", fi_FI="Haluatko varmasti vaihtaa käyttäjään %1? Järjestelmien ja kuljettajan\napujärjestelmien asetukset saattavat muuttua.", fr_FR="Souhaitez-vous vraiment passer au profil utilisateur %1? Les réglages du\nsystème et des aides au conducteur peuvent être différents.", hr_HR="Želite li se uistinu prebaciti na korisnika %1? Mogu se promijeniti sistemske\npostavke i postavke vozila.", hu_HU="Valóban át szeretnél váltani %1 felhasználóra? A rendszer és a\nvezetőasszisztensek beállításai megváltozhatnak.", it_IT="Passare all'utente %1? Le impostazioni dei sistemi e dell'assistenza al\nconducente potrebbero cambiare.", nl_NL="Wil je echt veranderen naar gebruiker %1? Systeem- en\nbestuurdershulpinstellingen zullen mogelijk veranderen.", no_NO="Er du sikker på at du vil bytte til brukeren %1? Systeminnstillinger og\ninnstillinger for førerassistentsystemer kan bli endret.", pl_PL="Czy na pewno chcesz zmienić użytkownika %1? Ustawienia systemu i asysty\nkierowcy mogą ulec zmianie.", pt_PT="Queres mesmo mudar para o utilizador %1? Os ajustes do sistema e da\nassistência à condução podem alterar-se.", ro_RO="Doriţi într-adevăr să schimbaţi la utilizatorul %1? Setările de sistem şi\nasistenţă a şoferului se pot modifica.", ru_RU="Вы действительно хотите переключиться на пользователя %1? Системные\nнастройки и настройки ассистирующих систем водителя могут измениться.", sk_SK="Skutočne sa chcete prepnúť na používateľa %1? Nastavenia systému a\nasistenta vodiča sa môžu zmeniť.", sl_SI="Ali res želite preklopiti na uporabnika %1? Sistemske nastavitve in nastavitve\nasistenčnih sistemov se lahko spremenijo.", sr_RS="Da li zaista želite da izmenite korisnika %1? Podešavanja sistema i asistencije\nza vozača mogu da se izmene.", sv_SE="Vill du verkligen byta till användaren %1? System- och\nförarassistansinställningar kan ändras.", tr_TR="Kullanıcıya %1 gerçekten geçmek istiyor musun? Sistem ve sürücü yardımı\nayarları değişebilir.", uk_UA="Ви дійсно хочете переключитися на користувача %1? Настройки системи та\nнастройки допоміжних систем для водія можуть змінитися.")
texttool_globals_dialog_message___user_data_sync_waiting_warning = TextObject(bs_BA="Individualne postavke Vašeg myAudi korisnika su aktualizirane. Želite li da ih\npreuzmete u vozilo?", cs_CZ="Individuální nastavení Vašeho uživatele myAudi byla aktualizována. Chcete je převzít\ndo vozidla?", da_DK="Din myAudi-brugers individuelle indstillinger blev opdateret. Vil du overføre dem til\nbilen?", de_DE="Die individuellen Einstellungen deines myAudi Nutzers wurden aktualisiert.\nMöchtest du diese ins Fahrzeug übernehmen?", el_GR="Έγινε ενημέρωση των επιμέρους ρυθμίσεων του λογαριασμού σας χρήστη myAudi.\nΘέλετε να τις υιοθετήσετε στο όχημα;", en_GB="The individual settings for your myAudi user have been updated. Would you like to\napply these in the vehicle?", es_ES="Los ajustes individuales de su usuario myAudi se han actualizado. ¿Desea aplicarlos\nen el vehículo?", fi_FI="myAudi-käyttäjän yksilölliset asetukset on päivitetty. Haluatko ottaa ne käyttöön\nautossa?", fr_FR="Les réglages personnels de votre profil utilisateur myAudi ont été actualisés.\nSouhaitez-vous les reprendre dans le véhicule?", hr_HR="Individualne postavke vašeg myAudi korisnika su aktualizirane. Želite li ih preuzeti u\nvozilo?", hu_HU="A myAudi felhasználód egyedi beállításai frissítésre kerültek. Át szeretnéd venni\nezeket a járműbe?", it_IT="Le impostazioni individuali dell'utente myAudi sono state aggiornate. Acquisirle\nsulla vettura?", nl_NL="De individuele instellingen van je myAudi gebruiker zijn bijgewerkt. Wil je ze\novernemen in het voertuig?", no_NO="De personlige innstillingene til myAudi-brukeren din er oppdatert. Vil du bruke dem\ni bilen?", pl_PL="Indywidualne ustawienia Twojego użytkownika myAudi zostały zaktualizowane. Czy\nchcesz, by zostały zastosowane w pojeździe?", pt_PT="Os ajustes individuais do teu utilizador myAudi foram atualizados. Desejas\nassumi-los no veículo?", ro_RO="Setările individuale ale utilizatorului myAudi au fost actualizate. Doriţi să le preluaţi\nîn autovehicul?", ru_RU="Индивидуальные настройки Вашего пользователя myAudi обновлены. Хотите\nприменить их в автомобиле?", sk_SK="Individuálne nastavenia vášho používateľa myAudi sa aktualizovali. Chcete ich\nprebrať do vozidla?", sl_SI="Individualne nastavitve uporabnika myAudi so bile posodobljene. Ali jih želite\nprevzeti v vozilo?", sr_RS="Individualna podešavanja vašeg myAudi korisnika su ažurirana. Da li ih želite\npreuzeti u vozilo?", sv_SE="De individuella inställningarna för din myAudi-användare har uppdaterats. Vill du\növerföra dem till fordonet?", tr_TR="myAudi kullanıcının kişisel ayarları güncellendi. Bunları araca devralmak ister\nmisin?", uk_UA="Індивідуальні настройки користувача myAudi оновлені. Хочете застосувати їх в\nавтомобілі?")
texttool_globals_dialog_message___user_data_sync_with_atne_waiting_warning = TextObject(bs_BA="Individualne postavke vašeg myAudi korisnika su aktualizirane. Želite li ih preuzeti u\nvozilo? To može uticati na aktivne postavke sistema za pomoć vozaču, sjedišta,\nupravljača i bočnih ogledala.", cs_CZ="Byla aktualizována individuální nastavení vašeho uživatele myAudi. Chcete je\npřenést do vozidla? To může mít vliv na nastavení aktivního asistenčního systému\nřidiče, nastavení sedadel, volantu a bočních zpětných zrcátek.", da_DK="Din myAudi-brugers individuelle indstillinger blev opdateret. Vil du overføre dem til\nbilen? Dette kan påvirke de aktive førerassistentsystemindstillinger, sæde-, rat- og\nsidespejlsindstillinger.", de_DE="Die individuellen Einstellungen deines myAudi Nutzers wurden aktualisiert.\nMöchtest du diese ins Fahrzeug übernehmen? Dies kann Auswirkungen auf aktive\nFahrerassistenzsystemeinstellungen, Sitz-, Lenkrad- und\nSeitenspiegeleinstellungen haben.", el_GR="Ενημερώθηκαν οι επιμέρους ρυθμίσεις του λογαριασμού χρήστη σας myAudi. Θέλατε\nνα τις μεταφέρετε στο όχημα; Αυτό μπορεί να επηρεάσει ενεργές ρυθμίσεις\nσυστημάτων υποβοήθησης οδηγού, ρυθμίσεις καθισμάτων, τιμονιού και πλευρικών\nκαθρεφτών.", en_GB="Your custom myAudi user settings have been updated. Do you want to send these\nto the vehicle? This could affect active driver assist settings, as well as  seat,\nsteering wheel and side mirror settings.", es_ES="Los ajustes personalizados de su usuario myAudi se han actualizado. ¿Desea\naplicarlos en el vehículo? Esto puede afectar a los ajustes que estén activos en los\nsistemas de asistencia al conductor y a los ajustes del asiento, del volante y de los\nretrovisores laterales.", fi_FI="myAudi-käyttäjän yksilölliset asetukset on päivitetty. Haluatko ottaa ne käyttöön\nautossa? Tämä voi vaikuttaa aktiivisten kuljettajaa avustavien järjestelmien\njärjestelmäasetuksiin, istuin-, ohjauspyörä- ja sivupeiliasetuksiin.", fr_FR="Les réglages personnels de votre profil utilisateur myAudi ont été actualisés.\nSouhaitez-vous les reprendre dans le véhicule? Cela peut avoir une influence sur les\nréglages des systèmes d'assistance du conducteur activés ainsi que sur les réglages\ndes sièges, du volant et des rétroviseurs extérieurs.", hr_HR="Individualne postavke vašeg myAudi korisničkog računa su aktualizirane. Želite li ih\npreuzeti u vozilo? To može imati posljedice po aktivne postavke sustava potpora za\nvozača, sjedala, kola upravljača i bočnih zrcala.", hu_HU="A myAudi felhasználód egyedi beállításai frissítésre kerültek. Át szeretnéd venni\nezeket a járműbe? Ez befolyásolhatja a vezetőtámogató rendszerek aktív\nbeállításait, valamint az ülés, a kormánykerék és az oldalsó tükrök beállításait.", it_IT="Le impostazioni individuali dell'utente myAudi sono state aggiornate. Acquisirle\nsulla vettura? Ciò può influire sulle impostazioni dei sistemi di assistenza alla guida\nattivi, dei sedili, del volante e degli specchi retrovisori.", nl_NL="De individuele instellingen van je myAudi gebruiker zijn geactualiseerd. Wil je deze\nin het voertuig overnemen? Dit kan gevolgen voor de actieve instellingen van het\nbestuurdershulpsysteem, stoel, stuur en zijspiegels hebben.", no_NO="De personlige innstillingene til myAudi-brukeren din er oppdatert. Vil du bruke dem\ni bilen? Innstillinger for førerassistentsystemer, sete, ratt og sidespeil kan bli\nendret.", pl_PL="Indywidualne ustawienia Twojego użytkownika myAudi zostały zaktualizowane. Czy\nchcesz, by zostały zastosowane w pojeździe? Może to mieć wpływ na ustawienia\naktywnego systemu wspomagania kierowcy, ustawienia siedzenia, kierownicy i\nlusterek bocznych.", pt_PT="Os ajustes individuais do teu utilizador myAudi foram atualizados. Queres\nassumi-los no veículo? Isto pode ter consequências nos ajustes dos sistemas de\nassistência à condução, nos ajustes dos bancos, do volante e nos ajustes dos\nespelhos laterais.", ro_RO="Setările individuale ale utilizatorului myAudi au fost actualizate. Doriţi să le preluaţi\nîn autovehicul? Aceasta poate avea efecte asupra setărilor active ale sistemelor de\nasistenţă a şoferului, ale scaunului, volanului şi oglinzilor laterale.", ru_RU="Индивидуальные настройки вашего пользователя myAudi были обновлены.\nХотите перенести их в автомобиль? Это может повлиять на настройки активных\nассистирующих систем, настройки сидений, рулевого колеса и боковых зеркал.", sk_SK="Individuálne nastavenia vášho používateľa myAudi boli aktualizované. Chcete tieto\nprevziať do vozidla? Môže to ovplyvniť nastavenia aktívneho podporného systému\nvodiča, nastavenia sedadla, volantu a bočných zrkadiel.", sl_SI="Individualne nastavitve uporabnika myAudi so bile posodobljene. Ali jih želite\nprevzeti v vozilo? To lahko vpliva na aktivne nastavitve asistenčnih sistemov ter\nnastavitve sedežev, volana in stranskih ogledal.", sr_RS="Individualna podešavanja vašeg myAudi korisnika su ažurirana. Da li želite da ih\npreuzmete u vozilo? To može da utiče na aktivna podešavanja sistema za asistenciju\nvozaču, sedišta, upravljača i bočnih ogledala.", sv_SE="De individuella inställningarna för din myAudi-användare har uppdaterats. Vill du\növerföra dem till fordonet? Detta kan påverka aktiva inställningar för\nförarassistanssystemen, sätena, ratten och ytterbackspeglarna.", tr_TR="myAudi kullanıcının kişisel ayarları güncellendi. Bunları araca devralmak ister\nmisin? Bu, aktif sürücü destek sistemi ayarlarına, koltuk, direksiyon simidi ve yan\nayna ayarlarına etki edebilir.", uk_UA="Індивідуальні налаштування вашого користувача myAudi було оновлено.\nБажаєте перенести їх до автомобіля? Це може вплинути на налаштування\nактивних допоміжних систем, налаштування сидінь, керма та бічних дзеркал.")
texttool_globals_dialog_message___wbl_generic_error_message = TextObject(bs_BA="Dodavanje novog korisnika nije bilo uspješno. Pokušajte ponovo kasnije.", cs_CZ="Přidání uživatele nebylo úspěšné. Zkuste to prosím později.", da_DK="Tilføjelse af bruger blev ikke gennemført korrekt. Forsøg igen senere.", de_DE="Das Hinzufügen des Nutzers war nicht erfolgreich. Bitte versuche es zu einem\nspäteren Zeitpunkt erneut.", el_GR="Η προσθήκη του χρήστη δεν ήταν επιτυχής. Προσπαθήστε πάλι αργότερα.", en_GB="Unable to add the user. Please try again later.", es_ES="El usuario no se ha podido añadir. Por favor, vuelva a intentarlo más tarde.", fi_FI="Käyttäjän lisääminen epäonnistui. Yritä myöhemmin uudelleen.", fr_FR="L'utilisateur n'a pas pu être ajouté. Veuillez réessayer ultérieurement.", hr_HR="Dodavanje korisnika nije bilo uspješno. Pokušajte ponovno kasnije.", hu_HU="A felhasználó hozzáadása sikertelen volt. Kérünk, próbáld újra később.", it_IT="Non è stato possibile aggiungere l'utente. Si prega di riprovare più tardi.", nl_NL="Het toevoegen van de gebruiker is niet gelukt. Probeer het op een later moment\nnog eens.", no_NO="Kan ikke legge til brukeren. Prøv igjen senere.", pl_PL="Dodawanie użytkownika nie powiodło się. Proszę spróbować ponownie później.", pt_PT="A introdução de um novo utilizador não foi bem sucedida. Por favor, volta a tentar\nmais tarde.", ro_RO="Adăugarea utilizatorului a eşuat. Reîncercaţi mai târziu.", ru_RU="Не удалось добавить пользователя. Пожалуйста, повторите попытку позже.", sk_SK="Pridanie používateľa nebolo úspešné. Prosím, pokúste sa o to znovu neskôr.", sl_SI="Dodajanje uporabnika ni bilo uspešno. Poskusite znova pozneje.", sr_RS="Dodavanje korisnika je bilo neuspešno. Pokušajte ponovo kasnije.", sv_SE="Det gick inte att lägga till användaren. Försök igen senare.", tr_TR="Kullanıcının eklenmesi başarısız oldu. Lütfen daha sonra yeniden dene.", uk_UA="Не вдалося додати користувача. Будь ласка, спробуйте пізніше.")
texttool_globals_dialog_message___wbl_profile_assigned_other_user_dialog_text = TextObject(bs_BA="Korisnik %1 već postoji na popisu korisnika. Želite li sada preći na ovog korisnika?", cs_CZ="Uživatel %1 již existuje v seznamu uživatelů. Chcete se nyní přepnout na tohoto\nuživatele?", da_DK="Brugeren %1 eksisterer allerede på brugerlisten. Vil du skifte til denne bruger nu?", de_DE="Der Nutzer %1 existiert bereits in der Nutzerliste. Möchtest du jetzt zu diesem\nNutzer wechseln?", el_GR="Ο χρήστης %1 υπάρχει ήδη στη λίστα χρηστών. Θέλετε να αλλάξετε τώρα σε αυτόν\nτον χρήστη;", en_GB="User %1 is already in the user list. Would you like to switch to this user now?", es_ES="El usuario %1 ya existe en la lista de usuarios. ¿Desea cambiar ahora a dicho\nusuario?", fi_FI="Käyttäjä %1 on jo käyttäjäluettelossa. Haluatko vaihtaa tähän käyttäjään nyt?", fr_FR="Le profil utilisateur %1 existe déjà dans la liste des profils. Souhaitez-vous accéder\nmaintenant à ce profil utilisateur?", hr_HR="Korisnik %1 već postoji u popisu korisnika. Želite li se sada prebaciti na tog\nkorisnika?", hu_HU="%1 felhasználó már létezik a felhasználólistán. Át szeretnél most váltani erre a\nfelhasználóra?", it_IT="L'utente %1 esiste già nella lista utenti. Si desidera passare adesso\na questo utente?", nl_NL="De gebruiker %1 komt al voor in de gebruikerlijst. Wil je nu naar deze gebruiker\noverschakelen?", no_NO="Brukeren %1 finnes allerede i brukerlisten. Vil du bytte til denne brukeren nå?", pl_PL="Użytkownik %1 już istnieje na liście użytkowników. Czy chcesz teraz przełączyć się\nna tego użytkownika?", pt_PT="O utilizador %1 já existe na lista de utilizadores. Queres mudar agora para este\nutilizador?", ro_RO="Utilizatorul %1 există deja în lista de utilizatori. Doriţi să comutaţi acum la acest\nutilizator?", ru_RU="Пользователь %1 уже существует в списке пользователей. Хотите\nпереключиться на этого пользователя сейчас?", sk_SK="Používateľ %1 už v zozname používateľov existuje. Chcete teraz zmeniť na tohto\npoužívateľa?", sl_SI="Uporabnik %1 že obstaja na seznamu uporabnikov. Ali želite zdaj preklopiti na tega\nuporabnika?", sr_RS="Korisnik %1 već postoji na listi korisnika. Da li sada želite da prebacite na ovog\nkorisnika?", sv_SE="Användaren %1 finns redan i användarlistan. Vill du byta till användaren nu?", tr_TR="Kullanıcı %1 zaten kullanıcı listesinde mevcut. Şimdi bu kullanıcıya geçmek ister\nmisin?", uk_UA="Користувач %1 уже існує у списку користувачів. Хочете переключитися на цього\nкористувача зараз?")
texttool_globals_dialog_message_with_decorator___guest_welcome__possible_remote_access = TextObject(bs_BA="Ovlaštenja za daljinski pristup su dodijeljena.", cs_CZ="Jsou přiřazena oprávnění ke vzdálenému přístupu.", da_DK="Fjernadgangstilladelser tildelt.", de_DE="Fernzugriffsberechtigungen sind vergeben.", el_GR="Έχουν χορηγηθεί δικαιώματα απομακρυσμένης πρόσβασης.", en_GB="Remote access rights assigned.", es_ES="Los permisos de acceso remoto están asignados.", fi_FI="Etäkäyttöoikeudet on myönnetty.", fr_FR="Des autorisations d'accès à distance sont attribuées.", hr_HR="Dodijeljena su ovlaštenja za daljinski pristup.", hu_HU="Távoli hozzáférési jogok megadva.", it_IT="Sono presenti diritti di accesso remoto.", nl_NL="Autorisaties bediening op afstand verleend.", no_NO="Det er gitt fjerntilgangsrettigheter.", pl_PL="Uprawnienia dostępu zdalnego zostały udzielone.", pt_PT="Permissões de acesso remoto estão concedidas.", ro_RO="Drepturile de acces de la distanţă sunt alocate.", ru_RU="Права на дистанционный доступ присвоены.", sk_SK="Oprávnenia na vzdialený prístup sú priradené.", sl_SI="Pooblastila za oddaljeni dostop so dodeljena.", sr_RS="Ovlašćenja za daljinski pristup su dodeljena.", sv_SE="Fjärråtkomstbehörigheter har tilldelats.", tr_TR="Uzaktan erişim izinleri atanmıştır.", uk_UA="Права на віддалений доступ присвоєно.")
texttool_globals_dialog_message_with_decorator___guest_welcome__primary_user = TextObject(bs_BA="Glavni korisnik je:\n%1 %2", cs_CZ="Hlavní uživatel je:\n%1 %2", da_DK="Den primære bruger er:\n%1 %2.", de_DE="Der Hauptnutzer ist:\n%1 %2", el_GR="Ο/Η βασικός/-ή χρήστης είναι ο/η:\n%1 %2", en_GB="The key user is:\n%1 %2", es_ES="El usuario principal es:\n%1 %2", fi_FI="Pääkäyttäjä on:\n%1 %2", fr_FR="L'utilisateur principal est:\n%1 %2", hr_HR="Glavni korisnik je:\n%1 %2", hu_HU="A főfelhasználó:\n%1 %2", it_IT="L'utente principale è:\n%1 %2", nl_NL="De hoofdgebruiker is:\n%1 %2", no_NO="Hovedbrukeren er:\n%1 %2", pl_PL="Użytkownikiem głównym jest:\n%1 %2", pt_PT="O utilizador principal é:\n%1 %2", ro_RO="Utilizatorul principal este:\n%1 %2", ru_RU="Основным пользователем является:\n%1 %2", sk_SK="Hlavný používateľ je:\n%1 %2", sl_SI="Glavni uporabnik je:\n%1 %2", sr_RS="Glavni korisnik je:\n%1 %2", sv_SE="Huvudanvändaren är:\n%1 %2", tr_TR="Ana kullanıcı %1\n%2 kişisidir", uk_UA="Основним користувачем є:\n%1 %2")
